    { name: { en: 'Semolina', ro: 'gris', ru: 'манная крупа', es: 'semola' }, measure: '2 Lbs' },
    { name: { en: 'Salt', ro: 'sare', ru: 'соль', es: 'sal' }, measure: '1 1/2 tsp' },
    { name: { en: 'Water', ro: 'apa', ru: 'вода', es: 'agua' }, measure: '3 Cups' },
    { name: { en: 'Olive Oil', ro: 'ulei de masline', ru: 'оливковое масло', es: 'aceite de oliva' }, measure: '4 tablespoons' },
    { name: { en: 'Olive Oil', ro: 'ulei de masline', ru: 'оливковое масло', es: 'aceite de oliva' }, measure: '6 tablespoons' }
