    { name: { en: 'Seafood stock', ro: 'supa de fructe de mare', ru: 'рыбный бульон', es: 'caldo de mariscos' }, measure: '650ml' },
    { name: { en: 'Squid', ro: 'calamar', ru: 'кальмар', es: 'calamar' }, measure: '3 Medium' }
